import{_ as o,o as e,c as a,a4 as d}from"./chunks/framework.4M7SpZrd.js";const m=JSON.parse('{"title":"Relatorios — Endpoints e Metricas","description":"","frontmatter":{},"headers":[],"relativePath":"api/reports.md","filePath":"api/reports.md"}'),r={name:"api/reports.md"};function s(i,t,c,n,l,p){return e(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="relatorios-—-endpoints-e-metricas" tabindex="-1">Relatorios — Endpoints e Metricas <a class="header-anchor" href="#relatorios-—-endpoints-e-metricas" aria-label="Permalink to &quot;Relatorios — Endpoints e Metricas&quot;">​</a></h1><blockquote><p><strong>Endpoints completos:</strong> <a href="http://kubex.test/api/docs#/reports" target="_blank" rel="noreferrer">Swagger UI — Reports</a></p></blockquote><hr><h2 id="endpoints" tabindex="-1">Endpoints <a class="header-anchor" href="#endpoints" aria-label="Permalink to &quot;Endpoints&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Endpoint</th><th>Descricao</th><th>Acesso</th></tr></thead><tbody><tr><td><code>GET /reports</code></td><td>Metricas agregadas (resumo)</td><td>Todos os planos</td></tr><tr><td><code>GET /reports/advanced</code></td><td>Breakdown por motor, tendencias, eficiencia de takedowns</td><td>Essencial+</td></tr><tr><td><code>GET /reports/export/csv</code></td><td>Exportacao CSV do relatorio avancado</td><td>Essencial+</td></tr><tr><td><code>GET /reports/face-search/{job_id}/pdf</code></td><td>Relatorio PDF de busca facial</td><td>Todos os planos</td></tr><tr><td><code>GET /reports/monitoring/monthly/pdf</code></td><td>Relatorio PDF de monitoramento mensal</td><td>Todos os planos</td></tr></tbody></table><p>Para detalhes dos relatorios PDF, ver <a href="./relatorios-pdf">Relatorios PDF</a>.</p><hr><h2 id="feature-flag-has-advanced-reports" tabindex="-1">Feature Flag: <code>has_advanced_reports</code> <a class="header-anchor" href="#feature-flag-has-advanced-reports" aria-label="Permalink to &quot;Feature Flag: `has_advanced_reports`&quot;">​</a></h2><p>Usuarios Free veem overlay de lock com CTA para upgrade. Configuravel via admin: <code>PATCH /admin/plans/{id}</code>.</p><hr><h2 id="relatorio-basico-get-reports" tabindex="-1">Relatorio Basico (<code>GET /reports</code>) <a class="header-anchor" href="#relatorio-basico-get-reports" aria-label="Permalink to &quot;Relatorio Basico (`GET /reports`)&quot;">​</a></h2><p>Metricas resumidas disponiveis para todos os planos:</p><ul><li>Total de buscas realizadas</li><li>Total de alertas recebidos</li><li>Total de takedowns enviados</li><li>Historico mensal (ultimos 6 meses)</li></ul><hr><h2 id="relatorio-avancado-get-reports-advanced" tabindex="-1">Relatorio Avancado (<code>GET /reports/advanced</code>) <a class="header-anchor" href="#relatorio-avancado-get-reports-advanced" aria-label="Permalink to &quot;Relatorio Avancado (`GET /reports/advanced`)&quot;">​</a></h2><p>10 secoes de metricas detalhadas:</p><table tabindex="0"><thead><tr><th>#</th><th>Secao</th><th>Descricao</th></tr></thead><tbody><tr><td>1</td><td>Deteccoes por motor</td><td>Breakdown de resultados por motor de busca</td></tr><tr><td>2</td><td>Eficiencia de takedowns</td><td>Taxa de sucesso (success rate) e tempo medio de resolucao</td></tr><tr><td>3</td><td>Detalhes de takedowns</td><td>Lista individual com status, tipo e datas</td></tr><tr><td>4</td><td>Tendencias</td><td>Variacao percentual vs periodo anterior (<code>null</code> = sem dados comparativos)</td></tr><tr><td>5</td><td>Top dominios infratores</td><td>Dominios com mais deteccoes de conteudo pirata</td></tr><tr><td>6</td><td>Distribuicao de confianca</td><td>Histograma de scores dos resultados</td></tr><tr><td>7</td><td>Funil alertas → takedowns</td><td>Conversion rate do pipeline de protecao</td></tr><tr><td>8</td><td>Verificacoes de takedown</td><td>Breakdown por metodo (HTTP, content check, pHash)</td></tr><tr><td>9</td><td>Utilizacao do plano</td><td>Quotas consumidas vs limites do plano</td></tr><tr><td>10</td><td>Cobertura de monitoramento</td><td>Plataformas monitoradas e frequencia</td></tr></tbody></table><h3 id="filtro-de-periodo" tabindex="-1">Filtro de Periodo <a class="header-anchor" href="#filtro-de-periodo" aria-label="Permalink to &quot;Filtro de Periodo&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Valor</th><th>Descricao</th></tr></thead><tbody><tr><td><code>7d</code></td><td>Ultimos 7 dias</td></tr><tr><td><code>30d</code></td><td>Ultimos 30 dias (default)</td></tr><tr><td><code>90d</code></td><td>Ultimos 90 dias</td></tr><tr><td><code>6m</code></td><td>Ultimos 6 meses</td></tr><tr><td><code>1a</code></td><td>Ultimo ano</td></tr></tbody></table><hr><h2 id="exportacao-csv-get-reports-export-csv" tabindex="-1">Exportacao CSV (<code>GET /reports/export/csv</code>) <a class="header-anchor" href="#exportacao-csv-get-reports-export-csv" aria-label="Permalink to &quot;Exportacao CSV (`GET /reports/export/csv`)&quot;">​</a></h2><p>Exporta os dados do relatorio avancado em formato CSV via <code>StreamingResponse</code>. Mesmo filtro de periodo.</p><hr><h2 id="frontend" tabindex="-1">Frontend <a class="header-anchor" href="#frontend" aria-label="Permalink to &quot;Frontend&quot;">​</a></h2><p>Pagina <code>/dashboard/relatorios</code> com duas abas:</p><ul><li><strong>Resumo</strong> — metricas basicas + historico 6 meses (todos os planos)</li><li><strong>Avancado</strong> — graficos Recharts + filtro de periodo + exportacao CSV (Essencial+)</li></ul>',26)])])}const u=o(r,[["render",s]]);export{m as __pageData,u as default};
